<?php
/** Sustainable Catalyst Lab v0.37.0 Reproducibility Packages and Research Publication Studio. */
if (!defined('ABSPATH')) { exit; }
final class SC_Lab_Publication_Studio_V0370 {
 const VERSION='0.37.0'; private static $initialized=false;
 public static function init(){if(self::$initialized){return;}self::$initialized=true;add_action('rest_api_init',array(__CLASS__,'routes'));add_filter('sc_lab_module_aliases_v02631',array(__CLASS__,'aliases'));add_filter('sc_lab_panel_aliases_v02631',array(__CLASS__,'aliases'));add_shortcode('sc_lab_publication_studio',array(__CLASS__,'shortcode'));add_shortcode('sc_lab_reproducibility_packages',array(__CLASS__,'shortcode'));}
 public static function aliases($aliases){$aliases=is_array($aliases)?$aliases:array();foreach(array('publication-studio','research-publication','reproducibility-packages','reproducibility-package','publication') as $alias){$aliases[$alias]='publication-studio';}return $aliases;}
