 public static function schema(){return rest_ensure_response(array('ok'=>true,'version'=>self::VERSION,'packageSchema'=>'sc-lab-reproducibility-package/0.37.0','publicationSchema'=>'sc-lab-research-publication/0.37.0','verificationSchema'=>'sc-lab-reproducibility-verification/0.37.0','exportSchema'=>'sc-lab-publication-export/0.37.0','eventSchema'=>'sc-lab-publication-event/0.37.0','immutableSealedPackages'=>true,'citationCff'=>true,'scientificSignoffGate'=>true,'embeddedRestrictedData'=>false,'arbitraryCode'=>false));}
 public static function health(){$required=array('assets/js/modules/publication-studio-v0370.js','assets/css/sc-lab-publication-studio-v0370.css','contracts/publication-studio-policy-v0370.json','contracts/reproducibility-package-v0370.schema.json','contracts/research-publication-v0370.schema.json','contracts/reproducibility-verification-v0370.schema.json','contracts/publication-export-v0370.schema.json','contracts/publication-event-v0370.schema.json','includes/class-sc-lab-publication-studio-v0370.php');$files=array();$ok=true;foreach($required as $relative){$files[$relative]=self::state($relative);if(empty($files[$relative]['exists'])){$ok=false;}}return rest_ensure_response(array('ok'=>$ok,'status'=>$ok?'ready':'incomplete','version'=>self::VERSION,'release'=>defined('SC_LAB_VERSION')?SC_LAB_VERSION:null,'architecture'=>'workspace-governed-reproducibility-packages-and-research-publication-studio','databaseSchemaVersion'=>1,'immutableSealedPackages'=>true,'publicationRendering'=>true,'scientificSignoffGate'=>true,'embeddedRestrictedData'=>false,'arbitraryCode'=>false,'hardDelete'=>false,'files'=>$files,'time'=>gmdate('c')));}
